	protected void populatePSAProjInvoiceHeaderTmp()
    {
        next populatePSAProjInvoiceHeaderTmp();

        FWFTextBlockReportTextInit::newParameters(this.tmpPSAProjInvoiceHeader, this.projInvoiceJour).addTexts();
